  "mongo/instance_list": `TIME-RANGE {duration:20s, etime:$etime}

CATEGORY stat

TAGLOAD {backward:true}

SELECT [ time, oid, cpu, active$connections, current$connections, insert$opcounters, query$opcounters, update$opcounters, delete$opcounters, command$opcounters ]

INJECT
--FIRST-ONLY {key:oid}

RENAME { src:insert$opcounters, dst:insert }
RENAME { src:query$opcounters, dst:query }
RENAME { src:update$opcounters, dst:update }
RENAME { src:delete$opcounters, dst:delete }
RENAME { src:command$opcounters, dst:command }
CREATE { key:executions, expr: "insert + query + update + delete + command" }

--CREATE { key:status, expr: "0" }

DELETE [ insert, query, update, delete, command ]

JOIN { query:'/mongo/event_status', pk:oid, field:[status] }
`,
