  "mongo/paramtest": "TIME-RANGE {duration:1d, etime:$etime}\n\nCATEGORY parameter\n\n--TAGLOAD\nTAGLOAD {backward:true}\nSELECT [time,pcode,oid]\nCREATE {key:hello, value:'hello10'}\nINJECT\nFIRST-ONLY {key:oid}\n",
