  "v2/db/db_mssql_active_session_count": `CATEGORY {"db_mssql_counter":6h, "db_mssql_counter{m5}":3d, "db_mssql_counter{h1}":unlimit }
OIDSET { oid:$oid, okind:$okind, onode:$onode }
TAGLOAD
SELECT [ 'pcode', 'time', 'oid', 'active_sessions', 'oname', 'dbName' ]
FILTER { key: "active_sessions", exist: true }
FILTER { key: "oname", exist: true }
FILTER { key: "dbName", value: ["TOTAL", ""] }

CREATE { key: _id_, expr: "pcode + '_' + oname" }
CREATE { key: _name_, expr: "oname" }

LAST-ONLY { key: _id_ }
ORDER { key: [oname, active_sessions], sort: [asc, desc] }`,
  "v2/db/db_mssql_long_active_session_count": `TIME-RANGE {duration: 15s, etime:$etime}
OIDSET { oid:$oid, okind:$okind, onode:$onode }

CATEGORY db_mssql_active_session
TAGLOAD
INJECT default
SELECT ['pcode','pname','oid','oname','time','id','elapse_time']
LAST-ONLY { key: oid }

UNFOLD [oid,time,oname,id,elapse_time]

CREATE { key:L1, expr:"elapse_time<3?1:0"}
CREATE { key:L2, expr:"elapse_time<10 && elapse_time >= 3 ?1:0"}
CREATE { key:L3, expr:"elapse_time<15 && elapse_time >= 10 ?1:0"}
CREATE { key:L4, expr:"elapse_time>=15?1:0"}

GROUP { timeunit:5000, pk: [oid, oname], merge:[L1,L2,L3,L4]}
UPDATE { key:[L1,L2,L3,L4], value:sum }
SELECT [pcode, oid, oname, L1, L2, L3, L4]

PIVOT-HEAD { key: ["oid", "oname"] }

CREATE { key: _id_, expr: "oid + '_' + pivot_field" }

CREATE { key: "color_key", expr: "pivot_field == 'L4' ? 'critical': '5'"}
CREATE { key: _name_, expr: "pivot_field == 'L4' ? '>= 15': '15 <'" }

IFUPDATE { if: "pivot_field == 'L3'", key: "color_key",  value: '5'}
IFUPDATE { if: "pivot_field == 'L3'", key: _name_, value: '< 15'}

IFUPDATE { if: "pivot_field == 'L2'", key: "color_key", value: '11'}
IFUPDATE { if: "pivot_field == 'L2'", key: _name_, value: '< 10'}

IFUPDATE { if: "pivot_field == 'L1'", key: "color_key", value: '1'}
IFUPDATE { if: "pivot_field == 'L1'", key: _name_, value: '< 3'}`,
  "v2/db/db_mssql_long_waiting_session_count": `TIME-RANGE {duration: 15s, etime:$etime}
OIDSET { oid:$oid, okind:$okind, onode:$onode }

CATEGORY db_mssql_lockinfo

TAGLOAD
INJECT default
SELECT ['pcode','pname','oid','oname','time','holder_id', 'waiter_id']
LAST-ONLY { key: oid }
UNFOLD ['pcode','pname','oid','oname','time','holder_id', 'waiter_id']

CREATE {key:id, from:"waiter_id"}
JOIN {pk: [id, oid], query:"active_session_query", field:[elapse_time]}

CREATE { key:L1, expr:"elapse_time<3?1:0"}
CREATE { key:L2, expr:"elapse_time<10 && elapse_time >= 3 ?1:0"}
CREATE { key:L3, expr:"elapse_time<15 && elapse_time >= 10 ?1:0"}
CREATE { key:L4, expr:"elapse_time>=15?1:0"}

GROUP { timeunit:5000, pk: [oid, oname], merge:[L1,L2,L3,L4]}
UPDATE { key:[L1,L2,L3,L4], value:sum }
SELECT [oid, oname, L1, L2, L3, L4]

PIVOT-HEAD { key: ["oid", "oname"] }

CREATE { key: _id_, expr: "oid + '_' + pivot_field" }

CREATE { key: "color_key", expr: "pivot_field == 'L4' ? 'critical': '5'"}
CREATE { key: _name_, expr: "pivot_field == 'L4' ? '>= 15': '15 <'" }

IFUPDATE { if: "pivot_field == 'L3'", key: "color_key",  value: '5'}
IFUPDATE { if: "pivot_field == 'L3'", key: _name_, value: '< 15'}

IFUPDATE { if: "pivot_field == 'L2'", key: "color_key", value: '11'}
IFUPDATE { if: "pivot_field == 'L2'", key: _name_, value: '< 10'}

IFUPDATE { if: "pivot_field == 'L1'", key: "color_key", value: '1'}
IFUPDATE { if: "pivot_field == 'L1'", key: _name_, value: '< 3'}

SUB active_session_query
TIME-RANGE {duration: 15s, etime:$etime}
OIDSET { oid:$oid, okind:$okind, onode:$onode }

CATEGORY db_mssql_active_session
TAGLOAD
INJECT default
SELECT ['pcode','pname','oid', 'time', 'oname', 'elapse_time', 'id']
UNFOLD ['elapse_time', 'id']
END`,
