      path: z.string().optional().describe(PARAM_MXQL_PATH),
      query: z.string().optional().describe(
        'PromQL expression to execute (e.g., "rate(node_cpu_seconds_total[5m])"). For reusable queries, use whatap_create_promql first.'
      ),
